def bitmask_dp(n, cost):
    """Minimum cost assignment using bitmask DP."""
    INF = float('inf')
    dp = [INF] * (1 << n)
    dp[0] = 0

    for mask in range(1 << n):
        if dp[mask] == INF:
            continue
        worker = bin(mask).count('1')
        if worker >= n:
            continue
        for job in range(n):
            if not (mask & (1 << job)):
                new_mask = mask | (1 << job)
                dp[new_mask] = min(dp[new_mask], dp[mask] + cost[worker][job])

    return dp[(1 << n) - 1]


